// frontend/src/components/jobs/JobDetails.js - Simplified without payment logic
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './JobDetails.css';

const JobDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user, isAuthenticated } = useAuth();
    const alert = useAlert();

    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [applying, setApplying] = useState(false);
    const [applicationData, setApplicationData] = useState({
        proposed_rate: '',
        message: ''
    });

    useEffect(() => {
        loadJobDetails();
    }, [id]);

    const loadJobDetails = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/jobs/${id}`);
            if (response.data.success) {
                setJob(response.data.data);
            } else {
                setError('Job not found');
            }
        } catch (error) {
            console.error('Error loading job:', error);
            setError('Failed to load job details');
        } finally {
            setLoading(false);
        }
    };

    const handleApply = async (e) => {
        e.preventDefault();
        if (!isAuthenticated) {
            alert.warning('Please login to apply');
            navigate('/login', { state: { from: `/jobs/${id}` } });
            return;
        }

        if (user?.user_type !== 'worker') {
            alert.error('Only workers can apply');
            return;
        }

        setApplying(true);
        setError('');

        try {
            const response = await api.post(`/jobs/${id}/apply`, {
                proposed_rate: parseInt(applicationData.proposed_rate),
                message: applicationData.message
            });

            if (response.data.success) {
                alert.success('✅ Application submitted!');
                setApplicationData({ proposed_rate: '', message: '' });
                loadJobDetails();
            }
        } catch (error) {
            console.error('Apply error:', error);
            alert.error(error.response?.data?.message || 'Failed to apply');
        } finally {
            setApplying(false);
        }
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'N/A';
        return new Date(dateString).toLocaleDateString();
    };

    if (loading) return <div className="loading-spinner">Loading...</div>;
    if (error) return <div className="error-container">{error}</div>;

    const isOwner = job?.client_id === user?.id;
    const hasApplied = job?.applications?.some(a => a.worker_id === user?.id);

    return (
        <div className="job-details-container">
            <div className="job-details">
                <h1>{job?.title}</h1>
                <div className="job-meta">
                    <span>📍 {job?.township}</span>
                    <span>💰 R{job?.budget_min} - R{job?.budget_max}</span>
                </div>

                <div className="job-description">
                    <h3>Description</h3>
                    <p>{job?.description}</p>
                </div>

                {user?.user_type === 'worker' && !isOwner && !hasApplied && (
                    <form onSubmit={handleApply} className="apply-form">
                        <h3>Apply for this job</h3>
                        <input
                            type="number"
                            placeholder="Your proposed rate (R)"
                            value={applicationData.proposed_rate}
                            onChange={(e) => setApplicationData({...applicationData, proposed_rate: e.target.value})}
                            required
                        />
                        <textarea
                            placeholder="Message to client (optional)"
                            value={applicationData.message}
                            onChange={(e) => setApplicationData({...applicationData, message: e.target.value})}
                            rows="3"
                        />
                        <button type="submit" disabled={applying}>
                            {applying ? 'Submitting...' : 'Apply for Job'}
                        </button>
                    </form>
                )}

                {hasApplied && <p>You have already applied for this job.</p>}
            </div>
        </div>
    );
};

export default JobDetails;
